window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2014>1>a>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"LIST OF SPECIMENS  Specimen A: Young maize plant  Specimen B: Male Inflorescence of maize plant  Specimen C: Female Inflorescence of maize plant  Specimen D: Maize grain  Specimen E: Rat/Mouse  Specimen F: Chicken/Domestic fowl  Specimen G: Mud wrap  Specimen L: Fresh uprooted grass species  Specimen M: Grasshopper  Specimen N: MushroomObserve specimens A, B, C and D closely and use them to answer questions 1(a) to 1(e).    Classify Specimen A Into its division and class.","images":[],"marking_scheme":"Classification of Specimen A: Division- Angiospermatophyta/Angiospermophyta/Magnoliophyta/Tracheophyta.    Class Monocotyledoneae/Liliopsida.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>a>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"State three observable features of specimen A which are characteristics of the class mentioned in 1(a)(i) above.","images":[],"marking_scheme":"- presence of narrow leaf/leaves  -Fibrous roots.  - Parallel venation on leaf,  - Presence of leaf sheath.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2014>1>b","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"b","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"State the relationship between specimen A and: (i) specimen B; (ii) specimen C; (iii) specimen D.","images":[],"marking_scheme":"B is male flower(s), male inflorescence of A .     C-is the female flower(s) female inflorescence of A.    D- is the fruit/seed of A.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>c>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"From. your observations of specimens B and C, what type of plant is specimen A?","images":[],"marking_scheme":"A monoecious plant","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>c>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Suggest the agent of pollination ot specimen B.","images":[],"marking_scheme":"Wind (not wind pollination or wind pollinated flower).","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>c>iii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State two reasons for the answer in 1(c)(i) above.","images":[],"marking_scheme":"- The flowers are dull in colour.  - The flowers are small/incospiscous  - Flowers lacks scent.  -The stigmas are borne on long flexible stvle/stigmas hand out to expose themselves to pollen grains.  - The stigmas are feathery.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>d","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"d","group":"","topic":"FRUITS","question":"Classify specimen D fully according to origin and structure.","images":[],"marking_scheme":"Full classification of Specimen D according to origin and structure: True; simple, dry indehiscent, caryopsis.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>1>e","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"e","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Make a drawing 8 cm 10 cm long of specimen C and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>a>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study specimens E and F carefully and use them to answer questions 2(a)(i) to 2(a)(ii).    State the Class to which each of specimens E and F belong.","images":[],"marking_scheme":"Specimen E-Mammalia. Specimen F-Aves.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>a>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"List four observable features each of specimens E and F.","images":[],"marking_scheme":"Specimen E   - Pinna/External ear.  -Body covered with fur/hair,  -mammary gland.  -Heterodont dentition.  -Whiskers; (five) clawed digits/pentadactyl limbs.    Specimen F  - Body covered with feathers;  -mouth modified into beak;  -legs have (horny) Scale.  -Fore-limb modified into wings/presence of wings;   -stream-lined body.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>a>iii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"iii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State how each of the observed features in 2(a)(i) adapt each of specimens E and F to their habitats.","images":[],"marking_scheme":"Specimen E  - enlarged external ear/Pinna for trapping sound waves.  -whiskers for detection of vibration of vibration/feeling its way througn burrows.  - Pear shape head/narrow body with folded legs for easy movement in burrows.  -Position of eyes on either side of the head allows wide range of view.  - Long (muscular) hind limbs for hopping/ jumping.  -Sharp incisors/heterodont dentition for nibbing vegetation/ mxed diet.  -Limbs end in claws used for scratching/digging.  -Body covered with fur/hair for temperature regulation.    Specimen F  - Forelimbs modified to wings for flying.  -Streamined body for easy movement through the air during flight.  - Possession of feathers on the body for temperature regulation.  -Tail feathers used for steering/balancing/brake/courtship display.  - Beak adapted for feeding.  -Clawed digits for scratching for food.  - Position of eyes/laterally placed eyes for wide vision.  -Quill feathers for flying","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>b>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study specimen G and use it to answer questions 2(b)(i) to 2(b)(ii).    Classify specimen G into its phylum and class.","images":[],"marking_scheme":"Phylum of G- Arthropoda. Class of G Insecta.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>b>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State four observable features of specimen G","images":[],"marking_scheme":"-(Upper part of) abdomen constricted into a waist/has a narrow waist.  - Two pairs of (membraneous) wings.  - Fore wings wings larger than hind wings.  -Wings are linked together by hooklets.  -Has piercing and biting mouthparts.  - Metameric segmentation.  - Bilaterally symmetrical.  - Three pairs of (thoracic) legs.  - Three body divisions head, thorax and. abdomen.  - Presence of exoskeleton (of chitin)  - one pair of antennae.  - One pair of compound eyes.  - Presence of jointed appendages.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>2>b>iii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Name one habitat of specimen G","images":[],"marking_scheme":"Mud nest on ceiling of buildings/wall/furniture.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2014>3>a>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study specimens L, M and N carefully and use them to answer questions 4(a) to 4(c).    State the habitats of specimens L, M and N.","images":[],"marking_scheme":"Specimen L- Grassland/farmland/garden.    Specimen M-Farmland/garden/grassland/field.    Specimen N-Moist/damp soil/environment/decaying tree/decaying wood/pastures/meadows.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>3>a>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"State the modes of nutrition of specimens L. M and N.","images":[],"marking_scheme":"Specimen L-autotrophic/photosynthetic/holophytic.   Specimen M- heterotrophic/holozoic Specimen N- Saprophytic.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>3>a>iii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"Explain how each of specimens L and M are adapted to their modes of feeding.","images":[],"marking_scheme":"Specimen L  - has green leaves/chlorophyll; for absorption of sunlight tor photosynthesis;   -root for absorption of water/nutrient/ minerals.    Specimen M   - It has mandible; for Cutting/chewing;   -Presence of labrum/maxilla; for cutting/chewing.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>3>b>i","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"i","group":"","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Describe briefly the relationship that exists among specimens L, M and N.","images":[],"marking_scheme":"Specimen L/grass produces food for Specimen M grasshopper; also serves as habitat for specimen M .  Decay/decomposition of Specimen L and M serve as food substrate for Specimen N.  -The decomposition activities of Specimen N provides nutrients for Specimen L.  - Specimen L releases oxygen during photosynthesis; which is used up by Specimen M and N respiration.  - Specimen M releases carbon-dioxide during respiration, for the use of Specimen L for photosynthesis.  - The excreta of Specimen M serves as nutrient for Specimen L and N.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>3>b>ii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"ii","group":"","topic":"PESTS","question":"State two ways in which specimen M is of economic importance.","images":[],"marking_scheme":"- Serves as source of income generations  - It destroys crops/plant/reduces crop yield/reduces income.  - It is edible/- Serves as food/source of food.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2014>3>b>iii","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"iii","group":"","topic":"PESTS","question":"State one way in which specimen M can be controlled.","images":[],"marking_scheme":"- Use or insecticide/pesticide.    - Introduction of biological enemies e.a birds/predators.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2014>3>c","subject":"Biology Practical","year":"2014","type":"Practical","sub_label":"c","group":"","topic":"PESTS","question":"Make a drawing 8cm - 10cm long of specimen M and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"}];